package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserTest {

    private File mockFile;
    private Charset charset;
    private CSVFormat mockFormat;

    @BeforeEach
    void setUp() {
        mockFile = mock(File.class);
        charset = Charset.defaultCharset();
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void testParseWithValidFileAndCharsetAndFormat() throws IOException {
        try (MockedConstruction<InputStreamReader> mockedReader = Mockito.mockConstruction(InputStreamReader.class,
                (mock, context) -> {
                    // no additional behavior needed
                })) {

            CSVParser parser = CSVParser.parse(mockFile, charset, mockFormat);
            assertNotNull(parser);
            assertEquals(mockFormat, parser.format);
        }
    }

    @Test
    void testParseWithNullFileThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(null, charset, mockFormat);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void testParseWithNullFormatThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockFile, charset, null);
        });
        assertEquals("format", thrown.getMessage());
    }
}
